import { ref, onMounted } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'
import store from '@/store'

export function useProfileData() {
  const resumeData = ref({
    name: '',
    gender: '',
    phone: '',
    email: '',
    location: '',
    birth_date: '',
    personal_summary: '',
    created_at: '',
    updated_at: ''
  })

  const loading = ref(false)
  const error = ref(null)

  const fetchInitialData = async () => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.getBasicInfo()
      console.log('Profile response:', response)

      if (response.data) {
        // 确保数据正确映射
        resumeData.value = {
          ...resumeData.value,
          name: response.data.name || '',
          gender: response.data.gender || '',
          phone: response.data.phone || '',
          email: response.data.email || '',
          location: response.data.location || '',
          birth_date: response.data.birth_date || '',
          personal_summary: response.data.personal_summary || '',
          created_at: response.data.created_at || '',
          updated_at: response.data.updated_at || ''
        }
      } else {
        throw new Error('获取资料失败：无数据返回')
      }
    } catch (err) {
      console.error('获取用户资料失败:', err)
      error.value = err.message || '获取用户资料失败'
      showToast(error.value, 'error')
    } finally {
      loading.value = false
    }
  }

  const updateResumeData = async (data) => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.updateBasicInfo(data)
      console.log('Update response:', response)

      if (response?.data) {
        // 更新本地数据
        resumeData.value = {
          ...resumeData.value,
          name: response.data.name || resumeData.value.name,
          gender: response.data.gender || resumeData.value.gender,
          phone: response.data.phone || resumeData.value.phone,
          email: response.data.email || resumeData.value.email,
          location: response.data.location || resumeData.value.location,
          birth_date: response.data.birth_date || resumeData.value.birth_date,
          personal_summary: response.data.personal_summary || resumeData.value.personal_summary,
          updated_at: response.data.updated_at || resumeData.value.updated_at
        }

        // 刷新用户信息
        await store.dispatch('fetchUserInfo')
        showToast('更新成功', 'success')
        return true
      }

      throw new Error(response?.message || '更新失败，请稍后重试')
    } catch (err) {
      console.error('更新用户资料失败:', err)
      error.value = err.message || '更新用户资料失败'
      showToast(error.value, 'error')
      return false
    } finally {
      loading.value = false
    }
  }

  onMounted(() => {
    fetchInitialData()
  })

  return {
    resumeData,
    loading,
    error,
    fetchInitialData,
    updateResumeData
  }
}
